const fs = require('fs');
const path = '/tmp/lead_queue.json';
const dmPath = '/tmp/lead_dms.json';

let q = { cycles: 0, leads: [] };
try { q = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

let dms = [];
try { dms = JSON.parse(fs.readFileSync(dmPath, 'utf8')); } catch(e) {}

const total = q.leads.length;
const newLeads = q.leads.filter(l => l.status === 'new').length;
const processing = q.leads.filter(l => l.status === 'processing').length;
const dmSent = q.leads.filter(l => l.status === 'dm_sent').length;

// Check for stuck processing leads (>15 min)
const now = Date.now();
const stuck = q.leads.filter(l => {
  if (l.status !== 'processing') return false;
  const added = new Date(l.added_at || l.dm_sent_at || now).getTime();
  return (now - added) > 15 * 60 * 1000;
});

const cycles = q.cycles || 0;

return {
  total_leads: total,
  new_leads: newLeads,
  processing: processing,
  dm_sent: dmSent,
  stuck_leads: stuck.map(l => l.business_name).join(', '),
  cycles_completed: cycles,
  total_dms_sent: dms.filter(d => d.type === 'initial').length,
  followups_sent: dms.filter(d => d.type === 'followup').length,
  health: stuck.length > 0 ? '⚠️ Stuck leads detected' : '✅ Healthy',
  should_alert: stuck.length > 0 || (cycles > 5 && newLeads === 0 && processing === 0)
};
